#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb(x) push_back(x)
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh(x) while(x)
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
using NP std;
il ll read()
{
    ll x=0,f=1;char ch=gc();
    wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
    return x*f;
}
void write(ll x)
{
    if(x<0)pc('-'),x=-x;
    if(x>9)write(x/10);
    pc(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
int n;
int main(void)
{
	n=read();
	vector<array<int,6>> a(n);
	set<array<int,6>> s;
	for(int i=0;i<n;++i)
	{
		for(int j=0;j<6;++j)
        {
            a[i][j]=read();
        }
		for(int j=0;j<6;++j)
		{
			array<int,6> b,d;
			for(int k=0;k<6;++k)
			{
				b[k] = a[i][(j+k)%6];
				d[k] = a[i][(j-k+6)%6];
			}
			if(s.find(b)!=s.end()||s.find(d)!=s.end())
			{
				puts("Twin snowflakes found.");
				return false;
			}
		}
		s.insert(a[i]); 
	}
    puts("No two snowflakes are alike.");
    return false;
}
